<template>
  <v-container fluid class="pa-6 pt-4 fill-height test">
    <v-row no-gutters class="fill-height">
      <v-sheet width="100%" height="33">
        <h3 class="font-weight-bold">{{ title }}</h3>
      </v-sheet>
      <v-sheet width="100%" height="calc(100% - 32px)" class="pt-2 overflow-hidden cctv-roi-manage-contents">
        <v-row no-gutters class="pa-0 fill-height">
          <v-card width="150" color="login_bg" class="pa-2 fill-height red">
            <v-list nav dense>
              <v-list-item-group v-model="selected" color="primary" class="login_bg">
                <template v-for="(item, i) in list">
                  <v-list-item :key="item.cctv_id" :disabled="item.cctv_id == selected" :input-value="item.cctv_id" :value="item.cctv_id" class="login_bg" @click="onCCTV(item)">
                    <v-list-item-content>
                      <v-list-item-title v-text="`${item.cctv_id}`" class="text-subtitle-2" />
                    </v-list-item-content>
                  </v-list-item>
                </template>
              </v-list-item-group>
            </v-list>
          </v-card>
          <v-col class="ml-4 fill-height overflow-x-hidden overflow-y-auto">
            <v-card width="100%" height="100%" outlined rounded="md" class="pa-3 px-5">
              <v-sheet height="33">
                <h3 class="font-weight-bold">{{ `${selectedItem.cctv_id}` }}</h3>
              </v-sheet>
              <v-sheet height="40" class="d-flex align-center">
                <template v-for="button in controlButton">
                  <v-btn
                    :key="button.id"
                    height="30"
                    color="btn_bg"
                    class="mr-2 px-0"
                    elevation="0"
                    outlined
                    rounded
                    :disabled="button.isDisable()"
                    small
                    :width="button.text ? 84 : 35"
                    @click="button.onClick"
                  >
                    <div class="font-weight-bold" :class="[button.isDisable() ? 'gray--text' : 'content--text']">
                      <v-icon size="14">{{ button.icon }}</v-icon>
                      <template v-if="button.text">
                        <span class="ml-1">{{ $t(button.text) }}</span>
                      </template>
                    </div>
                  </v-btn>
                </template>
                <v-spacer />
                <v-tooltip top>
                  <template #activator="{ on, attrs }">
                    <v-btn
                      icon
                      v-bind="attrs"
                      v-on="on"
                    >
                      <svg-icon width="20" height="20" icon-class="help" color="#e6e6e6" />
                    </v-btn>
                  </template>
                  <span>{{ `Ctrl + 휠` }}</span>
                </v-tooltip>
                <template v-for="(button, index) in scaleButton">
                  <v-btn
                    :key="`${button.id}_btn`"
                    height="30"
                    color="btn_bg"
                    class="mr-2 px-0"
                    elevation="0"
                    outlined
                    rounded
                    :disabled="button.isDisable()"
                    small
                    :width="button.text ? 84 : 35"
                    @click="button.onClick"
                  >
                    <div class="font-weight-bold" :class="[button.isDisable() ? 'gray--text' : 'content--text']">
                      <v-icon size="14">{{ button.icon }}</v-icon>
                      <template v-if="button.text">
                        <span class="ml-1">{{ $t(button.text) }}</span>
                      </template>
                    </div>
                  </v-btn>
                  <template v-if="index == 0">
                    <v-sheet width="50" class="ml-2 mr-4 text-center" :key="index">
                      <span>{{ `${scaleFactor * 10}%` }}</span>
                    </v-sheet>
                  </template>
                </template>
                <v-sheet width="416" />
              </v-sheet>
              <v-sheet width="100%" min-width="700" height="calc(100% - 33px - 40px)" class="pt-1" ref="roiContainer">
                <template v-if="isLoading">
                  <v-row no-gutters class="align-center justify-center fill-height">
                    <v-progress-circular indeterminate color="secondary" />
                  </v-row>
                </template>
                <template v-else>
                  <v-row no-gutters class="fill-height">
                    <v-col
                      class="pa-0 cctv-roi-manage-contents-image"
                      @mouseenter="onMouseEnter"
                      @mouseleave="onMouseLeave"
                      @wheel="onWheel"
                      ref="roiImage"
                    >
                      <v-sheet :width="scaleWidth/(scaleFactor / 0.1)" :height="scaleHeight/(scaleFactor / 0.1)" :style="`aspect-ratio: ${imageRatio}; transform: scale(${scaleFactor * 0.1}) !important;`">
                        <!--
                          Konva : Canvas 기반 드로잉 라이브러리
                        -->
                        <v-stage
                          ref="stage"
                          :config="configKonva"
                          @dblclick="onStageClick"
                          @mousemove="onStageMouseMove"
                          @contextmenu="onStageRightClick"
                        >
                          <v-layer>
                            <v-image
                              :config="{
                                image: cctvImg,
                                width: scaleWidth,
                                height: scaleHeight,
                                x: 0,
                                y: 0,
                              }"
                              :style="`aspect-ratio: ${imageRatio};`"
                            />
                            <!-- 모든 다각형 -->
                            <template v-for="(polygon, polygonIndex) in polygons">
                              <v-line
                                :key="`polygon-${polygonIndex}`"
                                :config="{
                                  points: polygon.points.flat(),
                                  stroke: polygonIndex === selectedPolygonIndex ? 'blue' : 'black',
                                  strokeWidth: polygonIndex === selectedPolygonIndex ? 3 : 2,
                                  lineJoin: 'round',
                                  closed: true,
                                  fill: polygonIndex === selectedPolygonIndex ? 'rgba(0, 255, 0, 0.5)' : 'rgba(0, 255, 0, 0.2)',
                                  draggable: polygonIndex === selectedPolygonIndex, // 선택된 다각형만 드래그 가능
                                }"
                                @click="onPolygonClick(polygonIndex, $event)"
                                @dragstart="onPolygonDragStart(polygonIndex, $event)"
                                @dragmove="onPolygonDragMove(polygonIndex, $event)"
                              />
                              <!-- 선택된 다각형의 꼭짓점 -->
                              <v-circle
                                v-if="polygonIndex === selectedPolygonIndex"
                                v-for="(point, pointIndex) in polygon.points"
                                :key="`circle-${polygonIndex}-${pointIndex}`"
                                :config="{
                                  x: point[0],
                                  y: point[1],
                                  radius: 5,
                                  fill: 'red',
                                  draggable: true,
                                }"
                                @dragstart="onCircleDragStart(polygonIndex, pointIndex, $event)"
                                @dragmove="onCircleDrag(polygonIndex, pointIndex, $event)"
                              />
                            </template>
                            <!-- 현재 그리고 있는 다각형 -->
                            <v-line
                              v-if="currentPolygon.points.length > 0"
                              :config="{
                                points: [...currentPolygon.points.flat(), ...mousePosition],
                                stroke: 'red',
                                strokeWidth: 2,
                                lineJoin: 'round',
                                closed: false,
                              }"
                            />
                            <!-- 현재 다각형의 꼭짓점 -->
                            <v-circle
                              v-for="(point, index) in currentPolygon.points"
                              :key="`current-circle-${index}`"

                              :config="{
                                x: point[0],
                                y: point[1],
                                radius: 5,
                                fill: 'red',
                                draggable: true,
                              }"
                              @dragstart="onCircleDragForCurrentStart(index, $event)"
                              @dragmove="onCircleDragForCurrent(index, $event)"
                            />
                          </v-layer>
                        </v-stage>
                      </v-sheet>
                    </v-col>
                    <span class="cctv-roi-manage-contents-image-info">{{ `* ${$t('magSafetyZoneInfo')}` }}</span>
                    <v-divider vertical class="mx-2" />

                    <v-sheet width="400" class="d-flex flex-column">
                      <v-btn @click="resetPolygons(true)">Reset</v-btn>
                      <v-btn @click="undo" :disabled="!canUndo">Undo</v-btn>
                      <v-btn @click="redo" :disabled="!canRedo">Redo</v-btn>
                      <v-btn @click="savePolygons(true)">Save</v-btn>
                      <!-- <v-col class="text-center overflow-hidden">
                        <h4 class="font-weight-bold secondary--text">{{ $t('safetyZoneCoord') }}</h4>
                        <v-card width="100%" outlined height="calc(100% - 27px - 8px)" class="mt-2 pa-3 overflow-y-auto text-left">
                          <template v-for="(point, point_index) in selectedItem.point_arr">
                            <v-chip :key="point_index" label class="mr-2 mb-2 text-caption">{{ `${point}` }}</v-chip>
                          </template>
                        </v-card>
                      </v-col> -->
                      <v-col class="text-center">
                        <h4 class="font-weight-bold secondary--text">모델 선택</h4>
                        <v-sheet width="100%" height="calc(100% - 27px - 8px)" class="mt-2 d-flex flex-row flex-wrap align-content-space-between">
                          <v-card width="100%" outlined class="pa-3">
                            <template v-for="(model, model_index) in modelList">
                              <v-checkbox
                                :key="model_index"
                                v-model="selectedItem[model.key]"
                                :label="model.text"
                                class="font-weight-medium"
                                :class="[{ 'mt-3' : model_index !== 0 }]"
                              />
                            </template>
                          </v-card>
                          <v-btn
                            height="36"
                            color="btn_bg"
                            class="mt-auto px-0"
                            elevation="0"
                            outlined
                            rounded
                            small
                            width="100%"
                            @click="saveRoi"
                          >
                            <div class="font-weight-bold content--text">
                              <!-- <v-icon size="14" class="mr-1">{{ button.icon }}</v-icon> -->
                              {{ `${$t('setupComplete')}` }}
                            </div>
                          </v-btn>
                        </v-sheet>
                      </v-col>
                    </v-sheet>
                  </v-row>
                </template>
              </v-sheet>
            </v-card>
          </v-col>
        </v-row>
        <span class="cctv-roi-manage-contents-mobile">해당 화면은 모바일 환경에서 지원되지 않습니다.</span>
      </v-sheet>
    </v-row>
  </v-container>
</template>

<script>

import { getUserCd } from '@/utils/token'
import { getRoiList, getImage, saveRoi } from '@/api/realTimeVideoSafetyManagement/safetyMonitoringZoneManage.js'

import baseview from '@/views/base/baseview.vue'
export default {
  mixins: [baseview],
  name: 'Test',
  components: {
  },
  data() {
    return {      title: this.$t('safetyMonitoringZoneManage'),
      selected: null,
      selectedItem: {},
      limitLength: 3,
      list: [],
      legacyList: [],
      controlButton: [
        { id: 'reset', text: 'reset', icon: 'mdi-refresh', isDisable: () => this.selectedItem.point_arr.length == 0, onClick: () => this.resetDraws(true) },
        { id: 'undo', text: 'undo', icon: 'mdi-undo', isDisable: () => this.pointsHistory.length == 0, onClick: () => this.undoDraws() },
        { id: 'redo', text: 'redo', icon: 'mdi-redo', isDisable: () => this.redoStack.length == 0, onClick: () => this.redoDraws() },
      ],
      scaleButton: [
        { id: 'scaleMinus', text: '', icon: 'mdi-minus', isDisable: () => this.scaleFactor == this.scaleMin, onClick: () => this.scaleFactor -= 1 },
        { id: 'scalePlus', text: '', icon: 'mdi-plus', isDisable: () => this.scaleFactor >= this.scaleMax, onClick: () => this.scaleFactor += 1 },
      ],
      isHovering: false,
      isLoading: true,
      configKonva: {
        width: 0,
        height: 0,
      },
      isPolygon: false,
      inputWidth: 900,
      inputHeight: 600,
      inputMin: 100,
      inputWidthMax: 1000,
      inputHeightMax: 800,
      scaleWidth: 0,
      scaleHeight: 0,
      imageRatio: 16/9,
      isScaleFactor: false,
      scaleFactor: 10,
      scaleMax: 20,
      scaleMin: 1,
      points: [], // 기존 좌표값
      originalPoints: [], // 원본 좌표값
      pointsHistory: [],
      redoStack: [],
      closeThreshold: 10,
      dragStartPos: { x: 0, y: 0 },
      cctvImg: null,
      selectModel: "Detection",
      modelList: [
        { text: '안전모 미착용, 위험구역 출입, 지게차 접근 감지', model_nm: 'Detection', key: 'detection' },
        { text: '작업자 쓰러짐', model_nm: 'Pose', key: 'pose' }
      ],
      originalWidth: 0, // 이미지 원본 너비
      originalHeight: 0, // 이미지 원본 높이


      /////////////////////////////////////////////////////////
      polygons: [], // 모든 다각형의 리스트
      currentPolygon: {
        points: [], // 현재 그리고 있는 다각형의 좌표
      },
      mousePosition: [0, 0], // 마우스의 실시간 위치
      selectedPolygonIndex: null, // 선택된 다각형 인덱스

      testUndoStack: [], // Undo 스택
      testRedoStack: [], // Redo 스택
    }

  },
  computed: {
    renderPolygons() {
      // 드래그 중에는 tempPolygons를 사용
      return this.tempPolygons.length ? this.tempPolygons : this.polygons
    },
    canUndo() {
      return this.testUndoStack.length > 0
    },
    canRedo() {
      return this.testRedoStack.length > 0
    }
  },
  async mounted() {
    await this.onMounted()
  },
  watch: {
    // selectedItem: {
    //   handler(val) {
    //     console.log('selectedItem?', val)
    //     const first = JSON.stringify(val.point_arr[0])
    //     const last = JSON.stringify(val.point_arr[val.point_arr.length - 1])
    //     if(val.point_arr.length >= this.limitLength && first == last) {
    //       this.isPolygon = true
    //     }
    //   },
    //   deep: true
    // }
  },
  methods: {
    onMounted() {
      getRoiList()
        .then(res => {
          this.list = res.list.map(el => {
            const { model_list, ...rest } = el
            const detection = model_list.find(el => el.model_nm == 'Detection')
            const pose = model_list.find(el => el.model_nm == 'Pose')?.is_run
            const coord = JSON.parse(detection['point_arr'] || "[]")
            return {
              ...rest,
              point_arr: coord,
              detection: detection['is_run'] || false,
              isPolygon: coord.length >= 3 ? true : false,
              pose: pose || false,
              polygons: []
            }
          })
          this.legacyList = JSON.parse(JSON.stringify(this.list))
          if(this.list.length !== 0) {
            if(this.selected == null) {
              this.selected = this.list[0].cctv_id
              this.selectedItem = this.list[0]
              this.isPolygon = this.list[0].isPolygon
            } else {
              this.selectedItem = this.list.find(el => el.cctv_id == this.selected)
            }
              this.handleImage(this.selected)
          }
        })
    },
    async handleImage(param) {
      this.isLoading = true
      await getImage(param)
        .then(async res => {
          const image = res.img_decode_data
          if(image) {
            this.originalWidth = res.img_size.width
            this.originalHeight = res.img_size.height
            this.inputWidth = res.img_size.width
            this.inputHeight = res.img_size.height
            let [x, y] = res.ratio ? res.ratio.split(':').map(Number) : [4, 3]
            this.imageRatio = x/y
            const byteCharacters = atob(image)
            const byteNumbers = new Array(byteCharacters.length).fill().map((_, i) => byteCharacters.charCodeAt(i))
            const byteArray = new Uint8Array(byteNumbers)
            const blob = new Blob([byteArray], { type: 'image/jpeg' })
            this.createImg(URL.createObjectURL(blob))
          }
        })
        .finally(() => {
          setTimeout(() => {
            this.isLoading = false
          }, 500)
        })
    },
    onCCTV(param) { 
      const previousSelected = this.selected
      let targetPolygon = this.legacyList.find(el => this.selectedItem.cctv_id === el.cctv_id)?.polygons
      let currentPolygon = this.polygons
      if (JSON.stringify(currentPolygon) !== JSON.stringify(targetPolygon)) {
        this.vToastifyPrompt(
          '수정된 사항이 있습니다. 저장하시겠습니까?',
          'info',
          async(current) => {
            await this.savePolygons(false)
            this.selected = param.cctv_id
            this.selectedItem = param
            this.handleImage(this.selected)
            this.resetDraws(false, param.isPolygon)
            this.resetPolygons(false)
          },
          () => {
            this.selected = previousSelected
          },
          true)
      } else {
        this.selected = param.cctv_id
        this.selectedItem = param
        this.handleImage(this.selected)
        this.resetDraws(false, param.isPolygon)
        this.resetPolygons(false)
      }
    },
    onMouseEnter() {
      this.isHovering = true
    },
    onMouseLeave() {
      this.isHovering = false
    },
    onWheel(event) {
      if (event.ctrlKey) {
        event.preventDefault()
        if (event.deltaY < 0 && this.scaleFactor < this.scaleMax) {
          this.scaleFactor++
        } else if (event.deltaY > 0 && this.scaleFactor > this.scaleMin) {
          this.scaleFactor--
        }
      }
    },
    handleMouseEnter(e) {
      const stage = e.target.getStage()
      stage.container().style.cursor = this.isPolygon ? 'pointer' : 'default'
    },
    handleMouseLeave(e) {
      const stage = e.target.getStage()
      stage.container().style.cursor = this.isPolygon ? 'pointer' : 'default'
    },
    createImg(imgParam) {
      const img = new Image()
      img.src = imgParam
      img.onload = () => {
        this.cctvImg = img
        this.originalWidth = img.width
        this.originalHeight = img.height
        if (this.isScaleFactor) {
          this.scaleWidth = img.width * this.scaleFactor
          this.scaleHeight = img.height * this.scaleFactor
        } else {
          this.scaleWidth = this.inputWidth
          this.scaleHeight = this.inputHeight
        }

        this.configKonva.width = this.scaleWidth
        this.configKonva.height = this.scaleHeight
        // this.updatePointsPosition()
      }
    },
    resetDraws(isForce, isPolygon) {
      if(isForce) {
        this.selectedItem.point_arr = []
      } else {
        this.selectedItem.point_arr = this.legacyList.find(el => el.cctv_id == this.selectedItem.cctv_id)?.point_arr || []
        // console.log(this.legacyList.find(el => el.cctv_id == this.selectedItem.cctv_id)?.point_arr || [])
      }
      this.pointsHistory = []
      this.redoStack = []
      if(isPolygon) {
        this.isPolygon = isPolygon
      } else {
        this.isPolygon = false
      }
    },
    undoDraws() {
      if (this.pointsHistory.length > 0) {
        this.redoStack.push(JSON.parse(JSON.stringify(this.selectedItem.point_arr)))
        this.selectedItem.point_arr = JSON.parse(JSON.stringify(this.pointsHistory.pop()))
        this.isPolygon = false
      }
    },
    redoDraws() {
      if (this.redoStack.length > 0) {
        this.savePointsHistory()
        this.selectedItem.point_arr = this.redoStack.pop()
        const [firstX, firstY] = this.selectedItem.point_arr[0]
        const [lastX, lastY] = this.selectedItem.point_arr[this.selectedItem.point_arr.length - 1]
        if (firstX === lastX && firstY === lastY) {
          isPolygon.value = true
        } else {
          isPolygon.value = false
        }
      }
    },
    endDraws() {
      this.isPolygon = true
    },
    onHandleClick(e) {
      if (this.isPolygon) return
      this.savePointsHistory()
      const pos = e.target.getStage().getPointerPosition()
      const lastPoint = this.selectedItem.point_arr[this.selectedItem.point_arr.length - 1]
      if (this.selectedItem.point_arr.length >= 3 && this.isClose(lastPoint, pos)) {
        this.endDraws()
      } else {
        const realX = Math.round(pos.x)
        const realY = Math.round(pos.y)
        const originalX = realX / this.scaleWidth * this.originalWidth
        const originalY = realY / this.scaleHeight * this.originalHeight
        this.selectedItem.point_arr.push([realX, realY])
        this.originalPoints.push([originalX, originalY])
      }
    },
    savePointsHistory() {
      this.pointsHistory.push(JSON.parse(JSON.stringify(this.selectedItem.point_arr)))
    },
    onHandleRightClick(e) {
      e.evt.preventDefault()
      if (this.selectedItem.point_arr.length >= 3) {
        this.endDraws()
      }
    },
    isClose(lastPoint, pos) {
      const dx = lastPoint[0] - pos.x
      const dy = lastPoint[1] - pos.y
      return Math.sqrt(dx * dx + dy * dy) <= this.closeThreshold
    },
    onDragStart(e) {
      this.dragStartPos = e.target.getStage().getPointerPosition()
    },
    onDragMove(e) {
      const pointerPosition = e.target.getStage().getPointerPosition()
      let deltaX = pointerPosition.x - this.dragStartPos.x
      let deltaY = pointerPosition.y - this.dragStartPos.y
      const minX = Math.min(...this.selectedItem.point_arr.map((p) => p[0]))
      const minY = Math.min(...this.selectedItem.point_arr.map((p) => p[1]))
      const maxX = Math.max(...this.selectedItem.point_arr.map((p) => p[0]))
      const maxY = Math.max(...this.selectedItem.point_arr.map((p) => p[1]))
      if (minX + deltaX < 0) {
        deltaX = -minX
      }
      if (minY + deltaY < 0) {
        deltaY = -minY
      }
      if (maxX + deltaX > this.scaleWidth) {
        deltaX = this.scaleWidth - maxX
      }
      if (maxY + deltaY > this.scaleHeight) {
        deltaY = this.scaleHeight - maxY
      }
      const x = Math.round(deltaX)
      const y = Math.round(deltaY)
      this.selectedItem.point_arr = this.selectedItem.point_arr.map(([px, py]) => [px + x, py + y])
      this.originalPoints = this.originalPoints.map(([opx, opy]) => [
        opx + (x / this.scaleWidth) * this.originalWidth,
        opy + (y / this.scaleHeight) * this.originalHeight,
      ])
      this.dragStartPos = pointerPosition
      e.target.position({ x: 0, y: 0 })
    },
    onPonintDragMove(index, e) {
      // if (this.isPolygon) {
        const pos = e.target.getStage().getPointerPosition()
        const realX = pos.x
        const realY = pos.y
        const originalX = realX / this.scaleWidth * this.originalWidth
        const originalY = realY / this.scaleHeight * this.originalHeight
  
        this.selectedItem.point_arr.splice(index, 1, [realX, realY])
        this.originalPoints.splice(index, 1, [originalX, originalY])
      // }
    },
    updatePointsPosition() {
      this.selectedItem.point_arr = this.originalPoints.map(([opx, opy]) => [
        (opx / this.originalWidth) * this.scaleWidth,
        (opy / this.originalHeight) * this.scaleHeight,
      ])
    },
    saveRoi() {
      if(this.selectedItem.cctv_id) {
        const point = JSON.parse(JSON.stringify(this.selectedItem.point_arr))
        if(point.length < 3) {
          this.vToastify(`${this.$t('msgReqValidateRoi')}`, 'warn')
          return
        }
        const handleSave = () => {
          this.openLoading('saving')
          const param = {
            cctv_id: this.selectedItem.cctv_id,
            model_list: this.modelList.map(el => ({
              userCd: getUserCd(),
              is_run: this.selectedItem[el.key],
              model_nm: el.model_nm,
              point_arr: JSON.stringify(el.key == 'pose' ? [] : point)
            }))
          }
          saveRoi([param], true)
            .then(res => {
              this.onMounted()
            })
            .finally(() => {
              this.endLoading()
            })
        }
        if(!this.isPolygon) {
          this.vToastifyPrompt(
          this.$t('msgReqValidateRoiNotPolygon'),
          'warn',
          current => {
            this.isPolygon = true
            handleSave()
          }, null, true)
        } else {
          this.vToastifyPrompt(
          this.$t('doSaveData'),
          'info',
          current => {
            handleSave()
          }, null, true)
        }
      }
    },




    // Konva 업데이트
    updateKonva() {
      this.$refs.layer.getNode().batchDraw(); // Konva 강제 재렌더링
    },
    // 현재 상태 저장
    saveState() {
      const currentState = {
        polygons : JSON.parse(JSON.stringify(this.polygons)),
        currentPolygon : JSON.parse(JSON.stringify(this.currentPolygon))
      }
      // const currentState = JSON.parse(JSON.stringify(this.polygons))
      this.testUndoStack.push(currentState) // 현재 상태를 Undo 스택에 저장
      this.testRedoStack = [] // 새로운 작업 시 Redo 스택 초기화
    },
    // Undo 동작
    undo() {
      if(this.canUndo){
        const previousState = this.testUndoStack.pop() // Undo 스택에서 이전 상태 가져오기
        let redo = {
          polygons : JSON.parse(JSON.stringify(this.polygons)),
          currentPolygon : JSON.parse(JSON.stringify(this.currentPolygon))
        }
        this.testRedoStack.push(redo) // 현재 상태를 Redo 스택에 저장
        this.polygons = previousState.polygons // 이전 상태로 복원
        this.currentPolygon = previousState.currentPolygon
        this.updateKonva() // UI 갱신
      }
    },
    // Redo 동작
    redo() {
      if(this.canRedo) {
        const nextState = this.testRedoStack.pop() // Redo 스택에서 다음 상태 가져오기
        let undo = {
          polygons : JSON.parse(JSON.stringify(this.polygons)),
          currentPolygon : JSON.parse(JSON.stringify(this.currentPolygon))
        }
        this.testUndoStack.push(undo) // 현재 상태를 Undo 스택에 저장
        this.polygons = nextState.polygons // 다음 상태로 복원
        this.currentPolygon = nextState.currentPolygon
        this.updateKonva() // UI 갱신
      }
    },

    /**
     * ROI 영역 다중 설정 테스트
     * 
     */
    onPolygonClick(polygonIndex, e) {
      e.cancelBubble = true // 클릭 이벤트 전파 방지
      this.selectedPolygonIndex = polygonIndex // 선택된 다각형 설정
    },
    onStageClick(e) {
      const pos = e.target.getStage().getPointerPosition()
      this.saveState()
      // 현재 다각형에 점 추가
      this.currentPolygon.points.push([pos.x, pos.y])
      const originalX = pos.x / this.scaleWidth * this.originalWidth
      const originalY = pos.y / this.scaleHeight * this.originalHeight
      this.originalPoints.push([originalX, originalY])
    },
    onStageMouseMove(e) {
      const pos = e.target.getStage().getPointerPosition()

      // 마우스 위치를 실시간으로 업데이트
      this.mousePosition = [pos.x, pos.y]
    },
    onStageRightClick(e) {
      e.evt.preventDefault()
      // 다각형 닫기 및 저장
      if (this.currentPolygon.points.length > 2) {
        this.polygons.push({ points: [...this.currentPolygon.points] })
        this.currentPolygon.points = []
      }
    },
    onCircleDragForCurrentStart(index, e) {
      const pos = e.target.getStage().getPointerPosition()
      this.saveState()
    },
    onCircleDragForCurrent(index, e) {
      const pos = e.target.getStage().getPointerPosition()
      // 현재 다각형의 점 위치 업데이트
      this.currentPolygon.points[index] = [pos.x, pos.y]
    },
    onCircleDragStart(polygonIndex, pointIndex, e) {
      const pos = e.target.getStage().getPointerPosition()
      this.saveState()
    },
    onCircleDrag(polygonIndex, pointIndex, e) {
      const pos = e.target.getStage().getPointerPosition()
      // Vue의 반응성을 유지하기 위해 배열을 수정
      this.$set(
        this.polygons[polygonIndex].points,
        pointIndex,
        [pos.x, pos.y]
      )
      // Konva 레이어 강제 재렌더링
      this.$refs.layer.getNode().batchDraw()
    },
    resetPolygons(isForce) {
      if(isForce) {
        this.polygons = []
        this.currentPolygon = { points: [] }
      } else {
        this.polygons = JSON.parse(JSON.stringify(this.legacyList.find(el => el.cctv_id == this.selectedItem.cctv_id)?.polygons || []))
      }
      this.testUndoStack = []
      this.testRedoStack = []
    },
    savePolygons(isForce) {
      if(isForce == true) {
        this.vToastifyPrompt(
          this.$t('doSaveData'),
          'info',
          current => {
            this.legacyList.find(el => el.cctv_id === this.selectedItem.cctv_id).polygons = JSON.parse(JSON.stringify(this.polygons))
            this.resetPolygons(false)
          }, null, true
        )
      }else {
        this.legacyList.find(el => el.cctv_id === this.selectedItem.cctv_id).polygons = JSON.parse(JSON.stringify(this.polygons))

      }

    },
    // 드래그 시작 시
    onPolygonDragStart(polygonIndex, e) {
      const pos = e.target.getStage().getPointerPosition()
      this.saveState()
      this.dragStartPos = pos // 드래그 시작 위치 저장
    },
    // 드래그 중
    onPolygonDragMove(polygonIndex, e) {
      const pos = e.target.getStage().getPointerPosition()
      // 이동 거리 계산
      let dx = pos.x - this.dragStartPos.x
      let dy = pos.y - this.dragStartPos.y

      const minX = Math.min(...this.polygons[polygonIndex].points.map((p) => p[0]))
      const minY = Math.min(...this.polygons[polygonIndex].points.map((p) => p[1]))
      const maxX = Math.max(...this.polygons[polygonIndex].points.map((p) => p[0]))
      const maxY = Math.max(...this.polygons[polygonIndex].points.map((p) => p[1]))
      if (minX + dx < 0) {
        dx = -minX
      }
      if (minY + dy < 0) {
        dy = -minY
      }
      if (maxX + dx > this.scaleWidth) {
        dx = this.scaleWidth - maxX
      }
      if (maxY + dy > this.scaleHeight) {
        dy = this.scaleHeight - maxY
      }
      const x = Math.round(dx)
      const y = Math.round(dy)
      this.polygons[polygonIndex].points = this.polygons[polygonIndex].points.map(([px, py]) => [px + x, py + y])
      this.originalPoints = this.originalPoints.map(([opx, opy]) => [
        opx + (x / this.scaleWidth) * this.originalWidth,
        opy + (y / this.scaleHeight) * this.originalHeight,
      ])
      this.dragStartPos = pos
      e.target.position({ x: 0, y: 0 })

      // Konva 레이어 재렌더링
      this.updateKonva()
    },
  },
  // beforeRouteLeave(to, from, next) {
  //   window.removeEventListener('resize', this.onWheel)
  //   next()
  // }
}
</script>

